#include <bits/stdc++.h>
using namespace std;

void solve() {
    long long n;
    cin >> n;

    int count = 0;
    do {
        count++;
        n /= 10;
    } while (n > 0);

    cout << count << "\n";
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int t; cin >> t;
    while (t--) solve();
    return 0;
}
